// frontend/src/components/SearchSection.jsx
import React, { useState, useEffect } from "react";

export default function SearchSection({ onSearch, defaultValue = "", loading = false }) {
  const [q, setQ] = useState(defaultValue);

  useEffect(() => { setQ(defaultValue); }, [defaultValue]);

  const submit = (e) => {
    e.preventDefault();
    const v = q.trim();
    if (!v) return;
    onSearch?.(v);
  };

  return (
    <form onSubmit={submit} className="w-full max-w-3xl mx-auto px-4 mt-4">
      <div className="flex gap-2">
        <input
          className="flex-1 rounded-xl bg-black/60 text-white placeholder-white/60 px-4 py-3 outline-none"
          placeholder="Search city, e.g., Atlanta,US"
          value={q}
          onChange={(e) => setQ(e.target.value)}
        />
        <button
          type="submit"
          disabled={loading}
          className="rounded-xl px-4 py-3 bg-purple-600 text-white disabled:opacity-60"
        >
          {loading ? "Loading..." : "Search"}
        </button>
      </div>
    </form>
  );
}
